mapper.select:
SELECT * FROM record_practice
WHERE student_id = #{studentId}
ORDER BY start_date DESC

mapper.insert:
INSERT INTO record_practice (
    student_id, activity_name, organization, start_date, end_date, content, proof_file
) VALUES (
    #{studentId}, #{activityName}, #{organization}, #{startDate}, #{endDate}, #{content}, #{proofFile}
)

mapper.update:
UPDATE record_practice
activity_name = #{activityName}, organization = #{organization}, start_date = #{startDate}, end_date = #{endDate}, content = #{content}, proof_file = #{proofFile}
WHERE id = #{id}
